// ─── IMAGE LOADER (Jikan fallback for chars without embedded image) ─────
function useCharacterImages() {
  const [images, setImages] = useState(() => {
    // Initialize with embedded images
    const init = {};
    CHARACTERS.forEach(c => {
      if (EMBEDDED_IMAGES[c.id]) init[c.id] = EMBEDDED_IMAGES[c.id];
    });
    return init;
  });

  useEffect(() => {
    let cancelled = false;
    const toFetch = CHARACTERS.filter(c => !EMBEDDED_IMAGES[c.id]);
    const load = async () => {
      for (let i = 0; i < toFetch.length; i++) {
        if (cancelled) return;
        try {
          const res = await fetch(`https://api.jikan.moe/v4/characters/${toFetch[i].mal_id}`);
          if (res.ok) {
            const data = await res.json();
            const url = data?.data?.images?.webp?.image_url || data?.data?.images?.jpg?.image_url;
            if (url && !cancelled) setImages(prev => ({ ...prev, [toFetch[i].id]: url }));
          }
        } catch (e) { /* fallback */ }
        if (i < toFetch.length - 1) await new Promise(r => setTimeout(r, 350));
      }
    };
    if (toFetch.length > 0) load();
    return () => { cancelled = true; };
  }, []);

  return images;
}

// ─── SCORE RING ─────────────────────────────────────────────────────────
function ScoreRing({ score, size = 140, t }) {
  const { rank, color, glow } = getRank(score);
  const r = (size - 14) / 2;
  const circ = 2 * Math.PI * r;
  const offset = circ - (score / 100) * circ;
  return (
    <div style={{ position: "relative", width: size, height: size, animation: "bsr-fadein 0.6s ease" }}>
      <svg width={size} height={size} style={{ transform: "rotate(-90deg)", position: "absolute" }}>
        <circle cx={size / 2} cy={size / 2} r={r} fill="none" stroke={t.div} strokeWidth="7" />
        <circle cx={size / 2} cy={size / 2} r={r} fill="none" stroke={color} strokeWidth="7" strokeLinecap="round"
          strokeDasharray={circ} strokeDashoffset={offset}
          style={{ transition: "stroke-dashoffset 1s cubic-bezier(0.4,0,0.2,1), stroke 0.4s" }} />
      </svg>
      <div style={{ position: "absolute", inset: 0, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center" }}>
        <span style={{ fontFamily: "'Space Mono', monospace", fontSize: size * 0.3, fontWeight: 700, color, lineHeight: 1 }}>{score}</span>
        <span style={{ fontSize: 9, color: t.text3, letterSpacing: 2, marginTop: 1 }}>/ 100</span>
        <span style={{ fontFamily: "'Space Mono', monospace", fontSize: size * 0.16, fontWeight: 700, color, letterSpacing: 5, marginTop: 6, textShadow: glow }}>{rank}</span>
      </div>
    </div>
  );
}

