function getTag(w) {
  if (w >= 0.9) return { l: "BiS", bg: "rgba(255,45,85,0.12)", b: "rgba(255,45,85,0.3)", c: "#ff6b8a" };
  if (w >= 0.7) return { l: "Great", bg: "rgba(255,149,0,0.10)", b: "rgba(255,149,0,0.25)", c: "#ff9500" };
  if (w >= 0.5) return { l: "Good", bg: "rgba(52,199,89,0.10)", b: "rgba(52,199,89,0.25)", c: "#34c759" };
  if (w > 0) return { l: "Low", bg: "rgba(142,142,147,0.08)", b: "rgba(142,142,147,0.2)", c: "#8e8e93" };
  return { l: "Dead", bg: "rgba(72,72,74,0.06)", b: "rgba(72,72,74,0.15)", c: "#636366" };
}

// ─── CHARACTER CARD (rectangular) ───────────────────────────────────────
function CharCard({ character, isActive, onClick, imgUrl, t }) {
  const [imgErr, setImgErr] = useState(false);
  const hasImg = imgUrl && !imgErr;
  const cc = character.color;

  return (
    <div className="bsr-charCard" onClick={onClick} style={{
      position: "relative", borderRadius: 14, overflow: "hidden",
      aspectRatio: "3 / 4",
      border: isActive ? `2.5px solid ${cc}` : `1px solid ${t.cardBorder}`,
      boxShadow: isActive ? `0 4px 24px ${cc}30, 0 0 0 1px ${cc}44` : t.shadow,
      background: character.gradient,
    }}>
      {hasImg && (
        <img src={imgUrl} alt={character.name} onError={() => setImgErr(true)}
          style={{ position: "absolute", inset: 0, width: "100%", height: "100%", objectFit: "cover", objectPosition: "center 20%" }} />
      )}
      {!hasImg && (
        <div style={{ position: "absolute", inset: 0, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 36, fontWeight: 900, color: "rgba(255,255,255,0.25)", letterSpacing: 4 }}>
          {character.initials}
        </div>
      )}
      <div style={{ position: "absolute", bottom: 0, left: 0, right: 0, height: "60%", background: "linear-gradient(to top, rgba(0,0,0,0.85) 0%, rgba(0,0,0,0.4) 50%, transparent 100%)" }} />
      <div style={{ position: "absolute", bottom: 0, left: 0, right: 0, padding: "10px 12px" }}>
        <div style={{ fontFamily: "'Outfit'", fontSize: 13, fontWeight: 800, color: "#fff", textShadow: "0 1px 4px rgba(0,0,0,0.6)", lineHeight: 1.2, marginBottom: 3 }}>
          {character.name}
        </div>
        <div style={{ display: "flex", alignItems: "center", gap: 4 }}>
          <span style={{ fontSize: 8, fontWeight: 900, padding: "1px 5px", borderRadius: 4, background: character.rarity === "SSR" ? "rgba(255,215,0,0.3)" : "rgba(255,149,0,0.3)", color: character.rarity === "SSR" ? "#ffd700" : "#ff9500", fontFamily: "'Outfit'", letterSpacing: 0.5 }}>{character.rarity}</span>
          <span style={{ fontFamily: "'Outfit'", fontSize: 9, fontWeight: 600, color: "rgba(255,255,255,0.6)", letterSpacing: 0.5 }}>{character.set_bis}</span>
        </div>
      </div>
      {character.coming_soon && (
        <div style={{ position: "absolute", top: 8, right: 8, background: character.rarity === "SR" ? "rgba(255,149,0,0.85)" : "rgba(108,59,170,0.85)", color: "#fff", fontSize: 9, fontWeight: 800, padding: "3px 8px", borderRadius: 6, fontFamily: "'Outfit'", letterSpacing: 0.5, backdropFilter: "blur(4px)" }}>{character.rarity === "SR" ? "WIP" : "SOON"}</div>
      )}
      {isActive && (
        <div style={{ position: "absolute", top: 8, right: 8, width: 24, height: 24, borderRadius: "50%", background: cc, display: "flex", alignItems: "center", justifyContent: "center", boxShadow: `0 2px 8px ${cc}66` }}>
          <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="#fff" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><polyline points="20 6 9 17 4 12" /></svg>
        </div>
      )}
    </div>
  );
}

// ─── STAMP CARD ─────────────────────────────────────────────────────────
function StampCard({ label, character, slot, weights, stamp, setStamp, score, t, isWinner, ov, L }) {
  const { mainStat, substats, procs = ["", "", ""], passive = "" } = stamp;
  const sd = STAMP_SLOTS[slot];
  const mc = checkMainStat(character, slot, mainStat, ov);
  const hasInput = mainStat || substats.some(s => s !== "");
  const allSubsFilled = substats.every(s => s !== "");
  const cc = character.color;

  const avail = (i) => {
    const used = substats.filter((s, j) => j !== i && s !== "");
    return ALL_SUBSTATS.filter(s => !used.includes(s));
  };

  const selStyle = (has) => ({
    width: "100%", background: t.input, border: `1px solid ${t.inputBorder}`,
    borderRadius: 10, padding: "10px 34px 10px 12px", color: has ? t.text : t.text3,
    fontSize: 13, outline: "none", cursor: "pointer", appearance: "none",
    fontFamily: "'Outfit', sans-serif", transition: "border-color 0.2s",
  });

  const chevron = (
    <div style={{ position: "absolute", right: 11, top: "50%", transform: "translateY(-50%)", pointerEvents: "none", color: t.text3, lineHeight: 0 }}>
      <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><polyline points="6 9 12 15 18 9" /></svg>
    </div>
  );

  return (
    <div className="bsr-card" style={{
      background: t.card, backdropFilter: "blur(24px)", WebkitBackdropFilter: "blur(24px)",
      border: isWinner ? `2px solid ${cc}66` : `1px solid ${t.cardBorder}`,
      borderRadius: 20, padding: 24, flex: 1, minWidth: 280, position: "relative", overflow: "hidden",
      boxShadow: isWinner ? `0 0 40px ${cc}12, ${t.shadow}` : t.shadow,
      transition: "all 0.35s ease, transform 0.2s",
    }}>
      <div style={{ position: "absolute", top: 0, left: 20, right: 20, height: 2, background: `linear-gradient(90deg, transparent, ${cc}44, transparent)` }} />
      {isWinner && (
        <div style={{ position: "absolute", top: 14, right: 14, background: `linear-gradient(135deg, ${cc}, ${cc}cc)`, color: "#fff", fontSize: 10, fontWeight: 800, padding: "4px 12px", borderRadius: 8, letterSpacing: 1, fontFamily: "'Outfit'", animation: "bsr-pulse 2s infinite" }}>★ {L.winner}</div>
      )}
      <div style={{ fontFamily: "'Outfit'", fontSize: 12, fontWeight: 700, color: t.text2, marginBottom: 20, textTransform: "uppercase", letterSpacing: 3 }}>{label}</div>
      <div style={{ marginBottom: 20 }}>
        <div style={{ fontFamily: "'Outfit'", fontSize: 10, color: t.text3, marginBottom: 6, fontWeight: 700, textTransform: "uppercase", letterSpacing: 1.5 }}>{L.mainStat}</div>
        <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
          <div style={{ position: "relative", flex: 1 }}>
            <select value={mainStat} onChange={e => setStamp({ ...stamp, mainStat: e.target.value })} style={selStyle(!!mainStat)}>
              <option value="" style={{ background: t.sel }}>{L.choose}</option>
              {sd.main_stats.map(s => <option key={s} value={s} style={{ background: t.sel }}>{s}</option>)}
            </select>
            {chevron}
          </div>
          {mc === "bis" && <span style={{ fontSize: 10, padding: "4px 10px", borderRadius: 8, background: "rgba(52,199,89,0.12)", color: "#34c759", border: "1px solid rgba(52,199,89,0.25)", fontWeight: 800, fontFamily: "'Outfit'", whiteSpace: "nowrap" }}>✓ BiS</span>}
          {mc === "off" && <span style={{ fontSize: 10, padding: "4px 10px", borderRadius: 8, background: "rgba(255,149,0,0.10)", color: "#ff9500", border: "1px solid rgba(255,149,0,0.2)", fontWeight: 800, fontFamily: "'Outfit'", whiteSpace: "nowrap" }}>Off</span>}
        </div>
      </div>
      <div style={{ marginBottom: 24 }}>
        <div style={{ fontFamily: "'Outfit'", fontSize: 10, color: t.text3, marginBottom: 8, fontWeight: 700, textTransform: "uppercase", letterSpacing: 1.5 }}>{L.substats}</div>
        <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
          {substats.map((sub, i) => {
            const w = sub ? (weights[sub] ?? 0) : -1;
            const tag = w >= 0 ? getTag(w) : null;
            return (
              <div key={i} style={{ display: "flex", alignItems: "center", gap: 8, animation: `bsr-fadein 0.3s ease ${i * 0.05}s both` }}>
                <div style={{ position: "relative", flex: 1 }}>
                  <select value={sub} onChange={e => { const n = [...substats]; n[i] = e.target.value; const np = (procs || ["", "", ""]).map(p => n.includes(p) ? p : ""); setStamp({ ...stamp, substats: n, procs: np }); }} style={selStyle(!!sub)}>
                    <option value="" style={{ background: t.sel }}>{L.substatN} {i + 1} —</option>
                    {avail(i).map(s => <option key={s} value={s} style={{ background: t.sel }}>{s}</option>)}
                  </select>
                  {chevron}
                </div>
                {tag && (
                  <span style={{ fontFamily: "'Outfit'", fontSize: 9, padding: "3px 9px", borderRadius: 6, fontWeight: 800, letterSpacing: 0.5, background: tag.bg, color: tag.c, border: `1px solid ${tag.b}`, minWidth: 40, textAlign: "center", textTransform: "uppercase" }}>{tag.l}</span>
                )}
              </div>
            );
          })}
        </div>
      </div>
      {allSubsFilled && (
        <div style={{ marginBottom: 24 }}>
          <div style={{ fontFamily: "'Outfit'", fontSize: 10, color: t.text3, marginBottom: 8, fontWeight: 700, textTransform: "uppercase", letterSpacing: 1.5 }}>{L.procs_title}</div>
          <div style={{ display: "flex", gap: 6 }}>
            {procs.map((proc, i) => (
              <div key={i} style={{ position: "relative", flex: 1 }}>
                <select value={proc} onChange={e => { const n = [...procs]; n[i] = e.target.value; setStamp({ ...stamp, procs: n }); }} style={{ ...selStyle(!!proc), fontSize: 11, padding: "8px 28px 8px 8px" }}>
                  <option value="" style={{ background: t.sel }}>{L.lvl} {[10, 15, 20][i]}</option>
                  {substats.filter(s => s !== "").map(s => <option key={s} value={s} style={{ background: t.sel }}>{s}</option>)}
                </select>
                {chevron}
              </div>
            ))}
          </div>
          <div style={{ fontFamily: "'Outfit'", fontSize: 9, color: t.text3, marginTop: 4, fontStyle: "italic" }}>{L.procs_note}</div>
        </div>
      )}
      {allSubsFilled && character.rarity === "SSR" && CHAR_PASSIVES[character.id] && (
        <div style={{ marginBottom: 24 }}>
          <div style={{ fontFamily: "'Outfit'", fontSize: 10, color: t.text3, marginBottom: 8, fontWeight: 700, textTransform: "uppercase", letterSpacing: 1.5 }}>{L.passive_title}</div>
          {CHAR_PASSIVES[character.id].recommended.length > 0 ? (
            <div>
              <div style={{ display: "flex", flexWrap: "wrap", gap: 6, marginBottom: 8 }}>
                {CHAR_PASSIVES[character.id].recommended.map((p, idx) => {
                  const isActive = passive === p;
                  const rankColors = ["#ff2d55", "#ff9500", "#ffd700", "#5ac8fa"];
                  const rankLabels = ["BiS", "#2", "#3", "#4"];
                  const tip = PASSIVE_TOOLTIPS[p] ? PASSIVE_TOOLTIPS[p][L._lang || "fr"] : "";
                  return (
                    <div key={p} style={{ position: "relative" }} className="bsr-tooltip-wrap">
                      <button onClick={() => setStamp({ ...stamp, passive: isActive ? "" : p })} style={{
                        display: "flex", alignItems: "center", gap: 6, padding: "6px 12px", borderRadius: 10,
                        border: isActive ? `2px solid ${rankColors[idx]}` : `1px solid ${t.cardBorder}`,
                        background: isActive ? `${rankColors[idx]}12` : t.input,
                        cursor: "pointer", fontFamily: "'Outfit'", fontSize: 11, fontWeight: 700,
                        color: isActive ? rankColors[idx] : t.text2, transition: "all 0.2s",
                      }}>
                        <span style={{ background: rankColors[idx], color: "#fff", fontSize: 8, fontWeight: 900, padding: "2px 5px", borderRadius: 4, letterSpacing: 0.5 }}>{rankLabels[idx]}</span>
                        {p}
                      </button>
                      {tip && <div className="bsr-tooltip">{tip}</div>}
                    </div>
                  );
                })}
              </div>
              <div style={{ position: "relative" }}>
                <select value={passive} onChange={e => setStamp({ ...stamp, passive: e.target.value })} style={{ ...selStyle(!!passive), fontSize: 11 }}>
                  <option value="" style={{ background: t.sel }}>{L.passive_none}</option>
                  {ALL_PASSIVES.filter(p => !CHAR_PASSIVES[character.id].recommended.includes(p)).map(p => (
                    <option key={p} value={p} style={{ background: t.sel }}>{p}</option>
                  ))}
                </select>
                {chevron}
              </div>
            </div>
          ) : (
            <div style={{ fontFamily: "'Outfit'", fontSize: 11, color: "#ff9500", fontStyle: "italic" }}>
              {CHAR_PASSIVES[character.id].note ? CHAR_PASSIVES[character.id].note[L._lang || "fr"] : ""}
            </div>
          )}
          {CHAR_PASSIVES[character.id].note && CHAR_PASSIVES[character.id].recommended.length > 0 && (
            <div style={{ fontFamily: "'Outfit'", fontSize: 9, color: t.text3, marginTop: 4, fontStyle: "italic" }}>
              {CHAR_PASSIVES[character.id].note[L._lang || "fr"]}
            </div>
          )}
        </div>
      )}
      {hasInput && score > 0 && (
        <div style={{ display: "flex", justifyContent: "center", paddingTop: 4 }}>
          <ScoreRing score={score} size={135} t={t} />
        </div>
      )}
      {hasInput && (
        <div style={{ textAlign: "center", marginTop: 12 }}>
          <button onClick={() => setStamp({ mainStat: "", substats: ["", "", "", ""], procs: ["", "", ""], passive: "" })} style={{ background: "none", border: "none", color: t.text3, fontSize: 11, cursor: "pointer", fontFamily: "'Outfit'", textDecoration: "underline", textUnderlineOffset: 3, padding: "4px 12px" }}>{L.reset}</button>
        </div>
      )}
    </div>
  );
}

// ─── WEIGHT BAR ─────────────────────────────────────────────────────────
function WBar({ stat, weight, max, cc, t }) {
  const pct = max > 0 ? (weight / max) * 100 : 0;
  return (
    <div style={{ display: "flex", alignItems: "center", gap: 10, fontFamily: "'Outfit'" }}>
      <span style={{ width: 140, fontSize: 12, color: weight > 0 ? t.text2 : t.text3, fontWeight: 500, whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>{stat}</span>
      <div style={{ flex: 1, height: 5, background: t.div, borderRadius: 3, overflow: "hidden" }}>
        <div style={{ width: `${pct}%`, height: "100%", borderRadius: 3, background: weight >= 0.9 ? cc : weight >= 0.7 ? `${cc}aa` : weight > 0 ? `${cc}55` : "transparent", transition: "width 0.6s ease" }} />
      </div>
      <span style={{ fontFamily: "'Space Mono', monospace", width: 28, textAlign: "right", fontSize: 11, fontWeight: 700, color: weight > 0 ? t.text : t.text3 }}>{weight}</span>
    </div>
  );
}

// ─── APP ─────────────────────────────────────────────────────────────────
export default function App() {
  const [mode, setMode] = useState("dark");
  const [lang, setLang] = useState("fr");
  const [rarityFilter, setRarityFilter] = useState("all");
  const [fullSetMode, setFullSetMode] = useState(false);
  const [setStamps, setSetStamps] = useState({ piece_1: { mainStat: "", substats: ["", "", "", ""], procs: ["", "", ""], passive: "" }, piece_2: { mainStat: "", substats: ["", "", "", ""], procs: ["", "", ""], passive: "" }, piece_3: { mainStat: "", substats: ["", "", "", ""], procs: ["", "", ""], passive: "" } });
  const L = LANG[lang];
  const builderRef = useRef(null);
  const [charId, setCharId] = useState("");
  const [slot, setSlot] = useState("piece_1");
  const [ov, setOv] = useState({});
  const [cmp, setCmp] = useState(false);
  const [weaponLv, setWeaponLv] = useState("");
  const [passiveLv, setPassiveLv] = useState("");
  const empty = { mainStat: "", substats: ["", "", "", ""], procs: ["", "", ""], passive: "" };
  const emptySlots = () => ({ piece_1: { a: { ...empty }, b: { ...empty } }, piece_2: { a: { ...empty }, b: { ...empty } }, piece_3: { a: { ...empty }, b: { ...empty } } });
  const [slotData, setSlotData] = useState(emptySlots());
  const sA = slotData[slot]?.a || empty;
  const sB = slotData[slot]?.b || empty;
  const setSA = (v) => setSlotData(prev => ({ ...prev, [slot]: { ...prev[slot], a: typeof v === "function" ? v(prev[slot].a) : v } }));
  const setSB = (v) => setSlotData(prev => ({ ...prev, [slot]: { ...prev[slot], b: typeof v === "function" ? v(prev[slot].b) : v } }));

  const images = useCharacterImages();
  const t = T[mode];
  const ch = CHARACTERS.find(c => c.id === charId) || null;

  useEffect(() => { if (charId && builderRef.current) { setTimeout(() => builderRef.current.scrollIntoView({ behavior: "smooth", block: "start" }), 100); } setSlotData(emptySlots()); setOv({}); setFullSetMode(false); setSetStamps({ piece_1: { mainStat: "", substats: ["", "", "", ""], procs: ["", "", ""], passive: "" }, piece_2: { mainStat: "", substats: ["", "", "", ""], procs: ["", "", ""], passive: "" }, piece_3: { mainStat: "", substats: ["", "", "", ""], procs: ["", "", ""], passive: "" } }); setSlot("piece_1"); setWeaponLv(""); setPassiveLv(""); }, [charId]);

  const w = useMemo(() => ch ? getEffectiveWeights(ch, ov, weaponLv, passiveLv) : {}, [ch, ov, weaponLv, passiveLv]);
  const scA = useMemo(() => ch ? calcScore(sA.substats, w, sA.procs, sA.passive, ch.id) : 0, [sA, w, ch]);
  const scB = useMemo(() => ch ? calcScore(sB.substats, w, sB.procs, sB.passive, ch.id) : 0, [sB, w, ch]);

  const fullSetScores = useMemo(() => {
    if (!ch || !fullSetMode) return { scores: [0, 0, 0], avg: 0 };
    const scores = ["piece_1", "piece_2", "piece_3"].map(s => {
      const st = setStamps[s];
      return calcScore(st.substats, w, st.procs, st.passive, ch.id);
    });
    const filled = scores.filter(s => s > 0);
    const avg = filled.length > 0 ? Math.round(filled.reduce((a, b) => a + b, 0) / filled.length) : 0;
    return { scores, avg };
  }, [setStamps, w, ch, fullSetMode]);
  const win = cmp && scA > 0 && scB > 0 ? (scA > scB ? "a" : scB > scA ? "b" : "tie") : null;
  const mx = ch ? Math.max(...Object.values(w)) : 1;

  return (
    <div style={{ minHeight: "100vh", background: t.bg, color: t.text, fontFamily: "'Outfit', -apple-system, sans-serif", transition: "background 0.4s, color 0.3s" }}>
      {ch && <div style={{ position: "fixed", top: -100, right: -100, width: "60vw", height: "60vh", background: `radial-gradient(ellipse, ${ch.color}06, transparent 70%)`, pointerEvents: "none", transition: "background 0.6s" }} />}
      <div style={{ maxWidth: 820, margin: "0 auto", padding: "0 16px 60px" }}>
        {/* HEADER */}
        <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", paddingTop: 28, paddingBottom: 4 }}>
          <div>
            <div style={{ fontSize: 9, letterSpacing: 5, textTransform: "uppercase", color: t.text3, fontWeight: 700 }}>Bleach: Soul Resonance</div>
            <h1 className="bsr-header" style={{ fontFamily: "'Outfit'", fontSize: 28, fontWeight: 900, margin: "4px 0 0", letterSpacing: -1, color: t.titleColor }}>Set Stamp Rater</h1>
            <a href="https://ko-fi.com/gota574" target="_blank" rel="noopener noreferrer" style={{ fontFamily: "'Outfit'", fontSize: 10, color: t.text3, textDecoration: "none", display: "inline-flex", alignItems: "center", gap: 4, marginTop: 4, transition: "color 0.2s" }} onMouseEnter={e => e.target.style.color = "#ff5e5b"} onMouseLeave={e => e.target.style.color = t.text3}>☕ {L.support_text}</a>
          </div>
          <div style={{ display: "flex", gap: 8 }}>
            <button onClick={() => setLang(l => l === "fr" ? "en" : "fr")} style={{ height: 44, padding: "0 14px", borderRadius: 12, border: `1px solid ${t.cardBorder}`, background: t.input, cursor: "pointer", fontSize: 13, fontWeight: 800, fontFamily: "'Outfit'", display: "flex", alignItems: "center", justifyContent: "center", gap: 6, transition: "all 0.3s", color: t.text2 }}><img src={lang === "fr" ? "data:image/svg+xml,%3Csvg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 900 600'%3E%3Crect fill='%23002395' width='300' height='600'/%3E%3Crect fill='%23fff' x='300' width='300' height='600'/%3E%3Crect fill='%23ED2939' x='600' width='300' height='600'/%3E%3C/svg%3E" : "data:image/svg+xml,%3Csvg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 60 30'%3E%3CclipPath id='a'%3E%3Cpath d='M0 0v30h60V0z'/%3E%3C/clipPath%3E%3CclipPath id='b'%3E%3Cpath d='M30 15h30v15zv15H0zH0V0zV0h30z'/%3E%3C/clipPath%3E%3Cg clip-path='url(%23a)'%3E%3Cpath d='M0 0v30h60V0z' fill='%23012169'/%3E%3Cpath d='M0 0l60 30m0-30L0 30' stroke='%23fff' stroke-width='6'/%3E%3Cpath d='M0 0l60 30m0-30L0 30' clip-path='url(%23b)' stroke='%23C8102E' stroke-width='4'/%3E%3Cpath d='M30 0v30M0 15h60' stroke='%23fff' stroke-width='10'/%3E%3Cpath d='M30 0v30M0 15h60' stroke='%23C8102E' stroke-width='6'/%3E%3C/g%3E%3C/svg%3E"} alt="" style={{ width: 20, height: 14, borderRadius: 2, objectFit: "cover" }} />{lang === "fr" ? "FR" : "EN"}</button>
            <button onClick={() => setMode(m => m === "dark" ? "light" : "dark")} style={{ width: 44, height: 44, borderRadius: 12, border: `1px solid ${t.cardBorder}`, background: t.input, cursor: "pointer", fontSize: 20, display: "flex", alignItems: "center", justifyContent: "center", transition: "all 0.3s" }}>{t.icon}</button>
          </div>
        </div>

        {/* CHARACTER GRID */}
        <div style={{ marginTop: 24, marginBottom: 24 }}>
          <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 12 }}>
            <div style={{ fontFamily: "'Outfit'", fontSize: 10, color: t.text3, fontWeight: 700, textTransform: "uppercase", letterSpacing: 2 }}>{L.character}</div>
            <div style={{ display: "flex", gap: 4 }}>
              {["all", "SSR", "SR"].map(r => {
                const active = rarityFilter === r;
                const label = r === "all" ? L.filter_all : r;
                return (
                  <button key={r} onClick={() => setRarityFilter(r)} style={{
                    fontFamily: "'Outfit'", fontSize: 10, fontWeight: 800, padding: "4px 12px", borderRadius: 8,
                    border: active ? "2px solid #ff9500" : `1px solid ${t.cardBorder}`,
                    background: active ? "rgba(255,149,0,0.12)" : t.input,
                    color: active ? "#ff9500" : t.text3, cursor: "pointer", transition: "all 0.2s",
                    letterSpacing: 0.5,
                  }}>{label}</button>
                );
              })}
            </div>
          </div>
          <div className="bsr-charGrid" style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(140px, 1fr))", gap: 12 }}>
            {CHARACTERS.filter(c => rarityFilter === "all" || c.rarity === rarityFilter).map(c => (
              <CharCard key={c.id} character={c} isActive={charId === c.id} onClick={() => setCharId(c.id)} imgUrl={images[c.id]} t={t} />
            ))}
          </div>
        </div>

        <div ref={builderRef} />
        {ch && ch.coming_soon ? (
          <div style={{ animation: "bsr-fadein 0.4s ease" }}>
            <div style={{ display: "flex", alignItems: "center", gap: 16, padding: "16px 20px", background: t.card, backdropFilter: "blur(24px)", border: `1px solid ${ch.color}22`, borderRadius: 18, marginBottom: 20, boxShadow: `0 0 24px ${ch.color}06` }}>
              <div style={{ width: 56, height: 56, borderRadius: 12, overflow: "hidden", flexShrink: 0, border: `2px solid ${ch.color}55`, background: ch.gradient, position: "relative" }}>
                {images[ch.id] ? (
                  <img src={images[ch.id]} alt="" style={{ width: "100%", height: "100%", objectFit: "cover", objectPosition: "center 20%" }} />
                ) : (
                  <div style={{ display: "flex", alignItems: "center", justifyContent: "center", height: "100%", fontSize: 18, fontWeight: 900, color: "rgba(255,255,255,0.3)" }}>{ch.initials}</div>
                )}
              </div>
              <div style={{ flex: 1 }}>
                <div style={{ fontFamily: "'Outfit'", fontSize: 20, fontWeight: 900, color: ch.color, letterSpacing: -0.5 }}>{ch.name}</div>
                <span style={{ fontFamily: "'Outfit'", background: `${ch.color}15`, color: ch.color, fontSize: 10, padding: "3px 10px", borderRadius: 8, fontWeight: 800, letterSpacing: 0.5 }}>{ch.set_bis}</span>
              </div>
            </div>
            <div style={{ background: t.card, border: `1px solid ${t.cardBorder}`, borderRadius: 20, padding: "60px 24px", textAlign: "center" }}>
              <div style={{ fontSize: 48, marginBottom: 16 }}>🚧</div>
              <div style={{ fontFamily: "'Outfit'", fontSize: 22, fontWeight: 900, color: ch.color, marginBottom: 8 }}>{L.coming_soon}</div>
              <div style={{ fontFamily: "'Outfit'", fontSize: 13, color: t.text2, lineHeight: 1.6 }}>{L.coming_soon_text(ch.name)}</div>
            </div>
          </div>
        ) : ch && (
          <div style={{ animation: "bsr-fadein 0.4s ease" }}>
            {/* SELECTED BANNER */}
            <div style={{ display: "flex", alignItems: "center", gap: 16, padding: "16px 20px", background: t.card, backdropFilter: "blur(24px)", border: `1px solid ${ch.color}22`, borderRadius: 18, marginBottom: 20, boxShadow: `0 0 24px ${ch.color}06` }}>
              <div style={{ width: 56, height: 56, borderRadius: 12, overflow: "hidden", flexShrink: 0, border: `2px solid ${ch.color}55`, background: ch.gradient, position: "relative" }}>
                {images[ch.id] ? (
                  <img src={images[ch.id]} alt="" style={{ width: "100%", height: "100%", objectFit: "cover", objectPosition: "center 20%" }} />
                ) : (
                  <div style={{ display: "flex", alignItems: "center", justifyContent: "center", height: "100%", fontSize: 18, fontWeight: 900, color: "rgba(255,255,255,0.3)" }}>{ch.initials}</div>
                )}
              </div>
              <div style={{ flex: 1 }}>
                <div style={{ fontFamily: "'Outfit'", fontSize: 20, fontWeight: 900, color: ch.color, letterSpacing: -0.5 }}>{ch.name}</div>
                <div style={{ display: "flex", alignItems: "center", gap: 8, marginTop: 3, flexWrap: "wrap" }}>
                  {ch.subtitle && <span style={{ fontSize: 12, color: t.text2, fontStyle: "italic" }}>{ch.subtitle}</span>}
                  <span style={{ fontFamily: "'Outfit'", background: `${ch.color}15`, color: ch.color, fontSize: 10, padding: "3px 10px", borderRadius: 8, fontWeight: 800, letterSpacing: 0.5 }}>{ch.set_bis}</span>
                </div>
                {ch.core_stamp && (
                  <div style={{ display: "flex", gap: 12, marginTop: 8, flexWrap: "wrap" }}>
                    <span style={{ fontFamily: "'Outfit'", fontSize: 9, color: t.text2 }}>🎯 {L.core_stamp}: <strong style={{ color: t.text }}>{ch.core_stamp}</strong></span>
                    <span style={{ fontFamily: "'Outfit'", fontSize: 9, color: t.text2 }}>⚔️ {L.weapon_stamp}: <strong style={{ color: t.text }}>{ch.weapon_stamp}</strong></span>
                  </div>
                )}
                {CHAR_GUIDES[ch.id] && (
                  <div style={{ fontFamily: "'Outfit'", fontSize: 10, color: t.text3, marginTop: 8, lineHeight: 1.5, fontStyle: "italic", borderLeft: `2px solid ${ch.color}33`, paddingLeft: 10 }}>
                    💡 {CHAR_GUIDES[ch.id][lang]}
                  </div>
                )}
              </div>
            </div>

            {/* SLOT */}
            <div style={{ marginBottom: 16 }}>
              <div style={{ fontFamily: "'Outfit'", fontSize: 10, color: t.text3, marginBottom: 8, fontWeight: 700, textTransform: "uppercase", letterSpacing: 2 }}>{L.piece}</div>
              <div className="bsr-slotBtns" style={{ display: "flex", gap: 8 }}>
                {Object.entries(STAMP_SLOTS).map(([k, v]) => {
                  const a = slot === k;
                  return (
                    <button key={k} onClick={() => setSlot(k)} style={{ flex: 1, padding: "12px 0", borderRadius: 12, cursor: "pointer", fontFamily: "'Outfit'", fontSize: 13, fontWeight: 800, letterSpacing: 0.5, border: a ? `2px solid ${ch.color}55` : `1px solid ${t.cardBorder}`, background: a ? `${ch.color}10` : t.input, color: a ? ch.color : t.text2, transition: "all 0.2s" }}>{v.label}</button>
                  );
                })}
              </div>
              <div style={{ fontFamily: "'Outfit'", fontSize: 11, color: t.text3, marginTop: 8 }}>
                ✦ {L.recommended} : {getEffectiveRecs(ch, slot, ov).join(" / ")}
              </div>
            </div>

            {/* OVERRIDES */}
            {ch.overrides && (
              <div style={{ marginBottom: 16, display: "flex", flexWrap: "wrap", gap: 8 }}>
                {ch.overrides.map(o => {
                  const a = !!ov[o.id];
                  return (
                    <label key={o.id} style={{ display: "flex", alignItems: "center", gap: 8, cursor: "pointer", fontFamily: "'Outfit'", background: a ? `${ch.color}12` : t.input, border: `1px solid ${a ? `${ch.color}44` : t.cardBorder}`, borderRadius: 10, padding: "8px 14px", fontSize: 12, fontWeight: 700, color: a ? ch.color : t.text2, transition: "all 0.2s", userSelect: "none" }}>
                      <input type="checkbox" checked={a} onChange={e => setOv({ ...ov, [o.id]: e.target.checked })} style={{ accentColor: ch.color, cursor: "pointer" }} />
                      {o.label}
                    </label>
                  );
                })}
              </div>
            )}

            {/* WEAPON STAMP & PASSIVE LEVELS */}
            {ch && !ch.coming_soon && (WEAPON_LEVELS[ch.id] || PASSIVE_LEVELS[ch.id]) && (
              <div style={{ marginBottom: 16, display: "flex", flexWrap: "wrap", gap: 8 }}>
                {WEAPON_LEVELS[ch.id] && (
                  <>
                    <span style={{ fontFamily: "'Outfit'", fontSize: 10, color: t.text3, fontWeight: 700, alignSelf: "center", textTransform: "uppercase", letterSpacing: 1 }}>{L.weapon_level}:</span>
                    {WEAPON_LEVELS[ch.id].levels.map(lv => {
                      const a = weaponLv === lv.id;
                      const hasData = Object.keys(lv.changes).length > 0;
                      const tip = lv.tooltip ? lv.tooltip[L._lang || "fr"] : "";
                      return (
                        <div key={lv.id} style={{ position: "relative" }} className="bsr-tooltip-wrap">
                          <button onClick={() => setWeaponLv(a ? "" : lv.id)} style={{
                            fontFamily: "'Outfit'", fontSize: 11, fontWeight: 700, padding: "5px 12px", borderRadius: 8,
                            border: a ? `2px solid ${ch.color}` : `1px solid ${t.cardBorder}`,
                            background: a ? `${ch.color}12` : t.input,
                            color: a ? ch.color : hasData ? t.text2 : t.text3,
                            cursor: "pointer", transition: "all 0.2s", opacity: hasData ? 1 : 0.5,
                          }}>{lv.label}</button>
                          {tip && <div className="bsr-tooltip">{tip}</div>}
                        </div>
                      );
                    })}
                  </>
                )}
                {PASSIVE_LEVELS[ch.id] && (
                  <>
                    <span style={{ fontFamily: "'Outfit'", fontSize: 10, color: t.text3, fontWeight: 700, alignSelf: "center", textTransform: "uppercase", letterSpacing: 1, marginLeft: 8 }}>{L.passive_level}:</span>
                    {PASSIVE_LEVELS[ch.id].levels.map(lv => {
                      const a = passiveLv === lv.id;
                      const hasData = Object.keys(lv.changes).length > 0;
                      const tip = lv.tooltip ? lv.tooltip[L._lang || "fr"] : "";
                      return (
                        <div key={lv.id} style={{ position: "relative" }} className="bsr-tooltip-wrap">
                          <button onClick={() => setPassiveLv(a ? "" : lv.id)} style={{
                            fontFamily: "'Outfit'", fontSize: 11, fontWeight: 700, padding: "5px 12px", borderRadius: 8,
                            border: a ? `2px solid ${ch.color}` : `1px solid ${t.cardBorder}`,
                            background: a ? `${ch.color}12` : t.input,
                            color: a ? ch.color : hasData ? t.text2 : t.text3,
                            cursor: "pointer", transition: "all 0.2s", opacity: hasData ? 1 : 0.5,
                          }}>{lv.label}</button>
                          {tip && <div className="bsr-tooltip">{tip}</div>}
                        </div>
                      );
                    })}
                  </>
                )}
              </div>
            )}

            {/* COMPARE + FULL SET */}
            <div style={{ display: "flex", justifyContent: "flex-end", gap: 8, marginBottom: 16 }}>
              <button onClick={() => setFullSetMode(!fullSetMode)} style={{ fontFamily: "'Outfit'", background: fullSetMode ? `${ch.color}10` : t.input, border: `1px solid ${fullSetMode ? `${ch.color}44` : t.cardBorder}`, borderRadius: 10, padding: "9px 18px", fontSize: 12, cursor: "pointer", color: fullSetMode ? ch.color : t.text2, fontWeight: 800, transition: "all 0.2s" }}>{fullSetMode ? `✕ ${L.full_set_close}` : L.full_set_btn}</button>
              <button onClick={() => { setCmp(!cmp); setSB({ mainStat: "", substats: ["", "", "", ""], procs: ["", "", ""], passive: "" }); }} style={{ fontFamily: "'Outfit'", background: cmp ? `${ch.color}10` : t.input, border: `1px solid ${cmp ? `${ch.color}44` : t.cardBorder}`, borderRadius: 10, padding: "9px 18px", fontSize: 12, cursor: "pointer", color: cmp ? ch.color : t.text2, fontWeight: 800, transition: "all 0.2s" }}>{cmp ? `✕ ${L.close}` : `⇔ ${L.compare}`}</button>
            </div>


            {fullSetMode && (
              <div style={{ marginBottom: 24, animation: "bsr-fadein 0.4s ease" }}>
                <div style={{ fontFamily: "'Outfit'", fontSize: 12, fontWeight: 800, color: t.text2, textTransform: "uppercase", letterSpacing: 2, marginBottom: 16 }}>{L.full_set}</div>
                <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
                  {["piece_1", "piece_2", "piece_3"].map((slotKey, si) => {
                    const st = setStamps[slotKey];
                    const sd = STAMP_SLOTS[slotKey];
                    const sc = calcScore(st.substats, w, st.procs, st.passive, ch.id);
                    const rk = getRank(sc);
                    const mc = checkMainStat(ch, slotKey, st.mainStat, ov);
                    return (
                      <div key={slotKey} style={{ background: t.card, border: `1px solid ${t.cardBorder}`, borderRadius: 14, padding: 16, backdropFilter: "blur(24px)" }}>
                        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 10 }}>
                          <div style={{ fontFamily: "'Outfit'", fontSize: 13, fontWeight: 800, color: ch.color }}>{sd.label}</div>
                          {sc > 0 && <div style={{ fontFamily: "'Space Mono', monospace", fontSize: 14, fontWeight: 700, color: rk.color }}>{rk.rank} ({sc}%)</div>}
                        </div>
                        <div style={{ display: "flex", gap: 6, marginBottom: 8, flexWrap: "wrap" }}>
                          <select value={st.mainStat} onChange={e => setSetStamps(prev => ({...prev, [slotKey]: {...prev[slotKey], mainStat: e.target.value}}))} style={{ flex: 1, minWidth: 120, background: t.input, border: `1px solid ${t.inputBorder}`, borderRadius: 8, padding: "6px 8px", color: st.mainStat ? t.text : t.text3, fontSize: 11, fontFamily: "'Outfit'", outline: "none", appearance: "none", cursor: "pointer" }}>
                            <option value="">{L.mainStat}</option>
                            {sd.main_stats.map(s => <option key={s} value={s}>{s}</option>)}
                          </select>
                          {mc === "bis" && <span style={{ fontSize: 9, padding: "3px 8px", borderRadius: 6, background: "rgba(52,199,89,0.12)", color: "#34c759", fontWeight: 800, fontFamily: "'Outfit'", alignSelf: "center" }}>✓ BiS</span>}
                          {mc === "off" && <span style={{ fontSize: 9, padding: "3px 8px", borderRadius: 6, background: "rgba(255,149,0,0.10)", color: "#ff9500", fontWeight: 800, fontFamily: "'Outfit'", alignSelf: "center" }}>Off</span>}
                        </div>
                        <div style={{ display: "flex", gap: 4, flexWrap: "wrap" }}>
                          {st.substats.map((sub, i) => (
                            <select key={i} value={sub} onChange={e => { const n = [...st.substats]; n[i] = e.target.value; setSetStamps(prev => ({...prev, [slotKey]: {...prev[slotKey], substats: n}})); }} style={{ flex: 1, minWidth: 80, background: t.input, border: `1px solid ${t.inputBorder}`, borderRadius: 8, padding: "6px 4px", color: sub ? t.text : t.text3, fontSize: 10, fontFamily: "'Outfit'", outline: "none", appearance: "none", cursor: "pointer" }}>
                              <option value="">Sub {i+1}</option>
                              {ALL_SUBSTATS.filter(s => !st.substats.filter((x,j) => j!==i && x).includes(s)).map(s => <option key={s} value={s}>{s}</option>)}
                            </select>
                          ))}
                        </div>
                      </div>
                    );
                  })}
                </div>
                {fullSetScores.avg > 0 && (
                  <div style={{ marginTop: 16, background: `${ch.color}08`, border: `2px solid ${ch.color}33`, borderRadius: 16, padding: 20, textAlign: "center" }}>
                    <div style={{ fontFamily: "'Outfit'", fontSize: 10, color: t.text3, textTransform: "uppercase", letterSpacing: 2, marginBottom: 8 }}>{L.full_set_rank}</div>
                    <div style={{ fontFamily: "'Space Mono', monospace", fontSize: 36, fontWeight: 900, color: getRank(fullSetScores.avg).color, textShadow: getRank(fullSetScores.avg).glow }}>{getRank(fullSetScores.avg).rank}</div>
                    <div style={{ fontFamily: "'Outfit'", fontSize: 18, fontWeight: 800, color: t.text, marginTop: 4 }}>{fullSetScores.avg}%</div>
                    <div style={{ fontFamily: "'Outfit'", fontSize: 11, color: t.text3, marginTop: 8 }}>
                      {["piece_1", "piece_2", "piece_3"].map((s, i) => {
                        const sc = fullSetScores.scores[i];
                        return sc > 0 ? <span key={s} style={{ margin: "0 8px", color: getRank(sc).color }}>{STAMP_SLOTS[s].label}: {sc}%</span> : null;
                      })}
                    </div>
                  </div>
                )}
              </div>
            )}
            {/* STAMP CARDS */}
            <div className="bsr-stampCards" style={{ display: "flex", gap: 16, flexWrap: "wrap" }}>
              <StampCard label="Stamp A" character={ch} slot={slot} weights={w} stamp={sA} setStamp={setSA} score={scA} t={t} isWinner={win === "a"} ov={ov} L={L} />
              {cmp && <StampCard label="Stamp B" character={ch} slot={slot} weights={w} stamp={sB} setStamp={setSB} score={scB} t={t} isWinner={win === "b"} ov={ov} L={L} />}
            </div>

            {/* COMPARISON RESULT */}
            {win && (
              <div style={{ textAlign: "center", marginTop: 16, padding: "14px 20px", fontFamily: "'Outfit'", background: t.card, borderRadius: 14, border: `1px solid ${t.cardBorder}`, fontSize: 14, fontWeight: 800, backdropFilter: "blur(24px)" }}>
                {win === "tie"
                  ? <span style={{ color: t.text2 }}>{L.tie}</span>
                  : <span style={{ color: ch.color }}>{L.wins(win === "a" ? "Stamp A" : "Stamp B", win === "a" ? scA : scB, win === "a" ? scB : scA)}</span>
                }
              </div>
            )}

            {/* WEIGHTS */}
            <div style={{ marginTop: 28, padding: "20px 24px", background: t.card, backdropFilter: "blur(24px)", borderRadius: 18, border: `1px solid ${t.cardBorder}` }}>
              <div style={{ fontFamily: "'Outfit'", fontSize: 10, color: t.text3, marginBottom: 14, fontWeight: 800, textTransform: "uppercase", letterSpacing: 2 }}>{L.priority}</div>
              <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
                {Object.entries(w).sort(([, a], [, b]) => b - a).map(([s, wt]) => (
                  <WBar key={s} stat={s} weight={wt} max={mx} cc={ch.color} t={t} />
                ))}
              </div>
            </div>
          </div>
        )}

        {/* EMPTY STATE */}
        {!ch && (
          <div style={{ textAlign: "center", padding: "40px 20px", color: t.text3, animation: "bsr-fadein 0.5s ease" }}>
            <svg width="52" height="52" viewBox="0 0 48 48" fill="none" stroke="currentColor" strokeWidth="1.2" opacity="0.3" style={{ animation: "bsr-float 3s ease-in-out infinite" }}>
              <line x1="10" y1="38" x2="36" y2="12" /><line x1="30" y1="12" x2="36" y2="12" /><line x1="36" y1="12" x2="36" y2="18" /><line x1="16" y1="28" x2="20" y2="32" />
            </svg>
            <div style={{ fontFamily: "'Outfit'", fontSize: 14, marginTop: 12 }}>{L.pick_char}</div>
          </div>
        )}

        <div style={{ textAlign: "center", marginTop: 48, padding: "24px 16px", borderTop: `1px solid ${t.div}` }}>
          <div style={{ fontFamily: "'Outfit'", fontSize: 11, color: t.text3, marginBottom: 10 }}>{L.support_footer}</div>
          <a href="https://ko-fi.com/gota574" target="_blank" rel="noopener noreferrer" style={{ display: "inline-flex", alignItems: "center", gap: 8, padding: "10px 24px", borderRadius: 12, background: "#ff5e5b", color: "#fff", fontFamily: "'Outfit'", fontSize: 13, fontWeight: 800, textDecoration: "none", letterSpacing: 0.5, transition: "transform 0.2s, box-shadow 0.2s", boxShadow: "0 4px 16px rgba(255,94,91,0.3)" }} onMouseEnter={e => { e.currentTarget.style.transform = "translateY(-2px)"; e.currentTarget.style.boxShadow = "0 6px 24px rgba(255,94,91,0.4)"; }} onMouseLeave={e => { e.currentTarget.style.transform = "translateY(0)"; e.currentTarget.style.boxShadow = "0 4px 16px rgba(255,94,91,0.3)"; }}>☕ {L.support_text} — Ko-fi</a>
          <div style={{ fontFamily: "'Outfit'", fontSize: 9, color: t.text3, marginTop: 12, letterSpacing: 2 }}>BSR SET STAMP RATER v5.0 — Fan-made tool</div>
        </div>
      </div>
    </div>
  );
}
